sql:
SELECT COUNT(*) AS total_reported_graffiti
FROM grafitti_reports
WHERE status = 'Reported';

SELECT name
FROM violators
WHERE city = 'New York';

external_knowledge:
- "Total fines" include the fine amount, administrative fee, and state fee;
- "Top 5 highest total fines" refers to the top 5 tickets within each city based on the total amount;
- "Exceed $1000" means the total amount is greater than 1000.

sql:
SELECT status
FROM grafitti_reports
WHERE grafitti_report_id = 1;

external_knowledge:
- "Traffic enforcement" refers to the practice of issuing tickets for traffic violations;
- "Total ticket counts" is the number of tickets issued by an agency;
- "Total fines collected" is the sum of all fines imposed by an agency;
- "Average fine per ticket" is the average amount of fines per ticket issued by an agency.

- 'Upheld' in the context of an appeal means the original decision has been confirmed by a higher authority;
- 'Amount due' is calculated as the total judgment amount minus the total amount already paid;
- 'Disposition' refers to the final decision or outcome of the ticket, such as 'Responsible by Default' or 'Not Responsible';
- 'Status' indicates the current state of the ticket, such as 'Open', 'Closed', or 'In-Progress'.

sql:
SELECT COUNT(*) AS total_violators
FROM violators
WHERE state = 'MI' AND city = 'DETROIT';

SELECT name, mailing_address_str_name
FROM violators
WHERE violator_id = 0;

SELECT name AS violator_name
FROM violators
ORDER BY name;

SELECT COUNT(*) AS violation_count
FROM tickets
WHERE violation_code = '1';

SELECT COUNT(*) AS total_tickets
FROM tickets
WHERE agency_id = 1;

external_knowledge:
- 'Top agencies' refers to the agencies with the highest total fines collected;
- 'Paid fines' are fines that have been fully paid;
- 'Total fines collected' is the sum of all fine amounts minus any discounts applied.

- "Heaviest purse" metaphorically refers to the inspector who has collected the highest cumulative amount of fees;
- "Coffers fill" metaphorically describes the accumulation of payments;
- "Violators" refers to individuals who have received tickets for violations.

sql:
SELECT SUM(cost) AS total_paid_cleanup_costs
FROM cleanup_costs
WHERE payment_status = 'Paid';

SELECT ticket_id, (fine_amount + admin_fee + state_fee + late_fee) AS total_amount
FROM tickets
ORDER BY total_amount DESC;
